import re

def render(template: str, ctx: dict) -> str:

    def resolve_path(path, context):
        parts = path.strip().split('.')
        val = context
        for part in parts:
            part = part.strip()
            if isinstance(val, dict) and part in val:
                val = val[part]
            else:
                raise KeyError(path)
        return val

    def eval_variable(inner, context):
        parts = [p.strip() for p in inner.split('|')]
        path = parts[0]
        filters = parts[1:]

        # Pre-validate all filters before doing any work
        for f in filters:
            if f == 'upper' or f == 'lower':
                pass
            elif f.startswith('default:'):
                pass
            else:
                raise ValueError(f"Unknown filter: {f!r}")

        has_default = any(f.startswith('default:') for f in filters)

        try:
            value = resolve_path(path, context)
        except KeyError:
            if has_default:
                value = None
            else:
                raise

        for f in filters:
            if f == 'upper':
                value = str(value).upper()
            elif f == 'lower':
                value = str(value).lower()
            elif f.startswith('default:'):
                arg = f[len('default:'):]
                # Strip surrounding quotes if present
                if len(arg) >= 2 and (
                    (arg[0] == '"' and arg[-1] == '"') or
                    (arg[0] == "'" and arg[-1] == "'")
                ):
                    arg = arg[1:-1]
                if value is None:
                    value = arg

        return str(value)

    token_re = re.compile(r'(\{\{.*?\}\}|\{%.*?%\})', re.DOTALL)
    tokens = token_re.split(template)

    def process(tokens, context):
        result = []
        i = 0
        while i < len(tokens):
            token = tokens[i]

            if token.startswith('{{') and token.endswith('}}'):
                inner = token[2:-2].strip()
                result.append(eval_variable(inner, context))
                i += 1

            elif token.startswith('{%') and token.endswith('%}'):
                tag_content = token[2:-2].strip()

                if tag_content.startswith('if '):
                    path = tag_content[3:].strip()

                    try:
                        cond = bool(resolve_path(path, context))
                    except KeyError:
                        cond = False

                    # Collect inner tokens until matching {% endif %}
                    i += 1
                    inner_tokens = []
                    depth = 1

                    while i < len(tokens):
                        t = tokens[i]
                        if t.startswith('{%') and t.endswith('%}'):
                            tc = t[2:-2].strip()
                            if tc.startswith('if '):
                                depth += 1
                                inner_tokens.append(t)
                            elif tc == 'endif':
                                depth -= 1
                                if depth == 0:
                                    i += 1  # consume the endif token
                                    break
                                else:
                                    inner_tokens.append(t)
                            else:
                                inner_tokens.append(t)
                        else:
                            inner_tokens.append(t)
                        i += 1

                    if depth != 0:
                        raise ValueError("Unbalanced if/endif: missing endif")

                    if cond:
                        result.append(process(inner_tokens, context))
                    # else: skip the inner block entirely

                elif tag_content == 'endif':
                    raise ValueError("Unbalanced if/endif: unexpected endif")

                else:
                    raise ValueError(f"Unknown tag: {tag_content!r}")

            else:
                result.append(token)
                i += 1

        return ''.join(result)

    return process(tokens, ctx)

